// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./interfaces/IERC20.sol";
import "./interfaces/IPancakeRouter02.sol";
import "./interfaces/IPancakeV3SwapRouter.sol";

/**
 * @title DustSwapRouterV2V3
 * @notice Enhanced router supporting both PancakeSwap V2 and V3
 * @dev Automatically routes through the version with better pricing
 */
contract DustSwapRouterV2V3 is Ownable, ReentrancyGuard {
    IPancakeRouter02 public immutable pancakeRouterV2;
    IPancakeV3SwapRouter public immutable pancakeRouterV3;
    IPancakeV3Quoter public immutable pancakeQuoterV3;
    address public immutable WBNB;

    // V3 pool fees: 100 = 0.01%, 500 = 0.05%, 2500 = 0.25%, 10000 = 1%
    uint24[] public v3PoolFees;

    enum RouterVersion {
        V2,
        V3,
        AUTO // Automatically choose best route
    }

    struct SwapConfig {
        address token;
        uint256 amount;
        uint256 minAmountOut;
        RouterVersion version;
        uint24 v3Fee; // Only used for V3
    }

    event BatchSwapCompleted(
        address indexed user,
        uint256 tokensSwapped,
        uint256 totalBNBReceived
    );

    event SingleSwapCompleted(
        address indexed user,
        address indexed tokenIn,
        uint256 amountIn,
        uint256 amountOut,
        RouterVersion version
    );

    event RouterVersionUsed(
        address indexed token,
        RouterVersion version,
        uint256 amountOut
    );

    error InvalidRouter();
    error InvalidToken();
    error TransferFailed();
    error DeadlineExpired();
    error EmptySwapList();
    error InvalidFee();

    /**
     * @notice Constructor
     * @param _pancakeRouterV2 Address of PancakeSwap Router V2
     * @param _pancakeRouterV3 Address of PancakeSwap Router V3
     * @param _pancakeQuoterV3 Address of PancakeSwap Quoter V3
     */
    constructor(
        address _pancakeRouterV2,
        address _pancakeRouterV3,
        address _pancakeQuoterV3
    ) Ownable(msg.sender) {
        if (_pancakeRouterV2 == address(0) || _pancakeRouterV3 == address(0)) {
            revert InvalidRouter();
        }

        pancakeRouterV2 = IPancakeRouter02(_pancakeRouterV2);
        pancakeRouterV3 = IPancakeV3SwapRouter(_pancakeRouterV3);
        pancakeQuoterV3 = IPancakeV3Quoter(_pancakeQuoterV3);
        WBNB = pancakeRouterV2.WETH();

        // Initialize common V3 pool fees
        v3PoolFees.push(100);   // 0.01%
        v3PoolFees.push(500);   // 0.05%
        v3PoolFees.push(2500);  // 0.25%
        v3PoolFees.push(10000); // 1%
    }

    /**
     * @notice Batch swap with automatic V2/V3 selection
     * @param tokens Array of token addresses
     * @param amounts Array of token amounts
     * @param minAmountsOut Array of minimum BNB amounts
     * @param deadline Transaction deadline
     */
    function batchSwapAuto(
        address[] calldata tokens,
        uint256[] calldata amounts,
        uint256[] calldata minAmountsOut,
        uint256 deadline
    ) external nonReentrant returns (uint256 totalBNBReceived) {
        if (block.timestamp > deadline) revert DeadlineExpired();
        if (tokens.length == 0) revert EmptySwapList();
        if (tokens.length != amounts.length || tokens.length != minAmountsOut.length) {
            revert("Array lengths mismatch");
        }

        uint256 initialBalance = address(this).balance;

        for (uint256 i = 0; i < tokens.length; i++) {
            if (tokens[i] == address(0) || tokens[i] == WBNB) revert InvalidToken();
            if (amounts[i] == 0) continue;

            // Transfer tokens from user
            IERC20 token = IERC20(tokens[i]);
            uint256 balanceBefore = token.balanceOf(address(this));
            bool transferSuccess = token.transferFrom(msg.sender, address(this), amounts[i]);
            if (!transferSuccess) revert TransferFailed();

            uint256 actualAmount = token.balanceOf(address(this)) - balanceBefore;

            // Determine best route (V2 or V3)
            (RouterVersion bestVersion, uint256 bestAmount, uint24 bestFee) =
                _getBestRoute(tokens[i], actualAmount);

            // Execute swap on best route
            if (bestVersion == RouterVersion.V2) {
                _swapV2(token, actualAmount, minAmountsOut[i], deadline);
            } else {
                _swapV3(token, actualAmount, minAmountsOut[i], bestFee);
            }

            emit RouterVersionUsed(tokens[i], bestVersion, bestAmount);
        }

        totalBNBReceived = address(this).balance - initialBalance;

        if (totalBNBReceived > 0) {
            (bool success, ) = payable(msg.sender).call{value: totalBNBReceived}("");
            if (!success) revert TransferFailed();
        }

        emit BatchSwapCompleted(msg.sender, tokens.length, totalBNBReceived);
    }

    /**
     * @notice Batch swap with manual router selection
     * @param configs Array of swap configurations
     * @param deadline Transaction deadline
     */
    function batchSwapManual(
        SwapConfig[] calldata configs,
        uint256 deadline
    ) external nonReentrant returns (uint256 totalBNBReceived) {
        if (block.timestamp > deadline) revert DeadlineExpired();
        if (configs.length == 0) revert EmptySwapList();

        uint256 initialBalance = address(this).balance;

        for (uint256 i = 0; i < configs.length; i++) {
            SwapConfig memory config = configs[i];

            if (config.token == address(0) || config.token == WBNB) revert InvalidToken();
            if (config.amount == 0) continue;

            // Transfer tokens from user
            IERC20 token = IERC20(config.token);
            uint256 balanceBefore = token.balanceOf(address(this));
            bool transferSuccess = token.transferFrom(msg.sender, address(this), config.amount);
            if (!transferSuccess) revert TransferFailed();

            uint256 actualAmount = token.balanceOf(address(this)) - balanceBefore;

            // Execute based on specified version
            if (config.version == RouterVersion.V2) {
                _swapV2(token, actualAmount, config.minAmountOut, deadline);
            } else if (config.version == RouterVersion.V3) {
                _swapV3(token, actualAmount, config.minAmountOut, config.v3Fee);
            } else {
                // AUTO mode
                (RouterVersion bestVersion, , uint24 bestFee) =
                    _getBestRoute(config.token, actualAmount);

                if (bestVersion == RouterVersion.V2) {
                    _swapV2(token, actualAmount, config.minAmountOut, deadline);
                } else {
                    _swapV3(token, actualAmount, config.minAmountOut, bestFee);
                }
            }
        }

        totalBNBReceived = address(this).balance - initialBalance;

        if (totalBNBReceived > 0) {
            (bool success, ) = payable(msg.sender).call{value: totalBNBReceived}("");
            if (!success) revert TransferFailed();
        }

        emit BatchSwapCompleted(msg.sender, configs.length, totalBNBReceived);
    }

    /**
     * @notice Get best route by comparing V2 and V3 quotes
     */
    function _getBestRoute(
        address token,
        uint256 amount
    ) internal returns (RouterVersion, uint256, uint24) {
        uint256 v2Quote = _getV2Quote(token, amount);
        (uint256 v3Quote, uint24 v3Fee) = _getBestV3Quote(token, amount);

        if (v2Quote >= v3Quote) {
            return (RouterVersion.V2, v2Quote, 0);
        } else {
            return (RouterVersion.V3, v3Quote, v3Fee);
        }
    }

    /**
     * @notice Get V2 quote
     */
    function _getV2Quote(address token, uint256 amount) internal view returns (uint256) {
        address[] memory path = new address[](2);
        path[0] = token;
        path[1] = WBNB;

        try pancakeRouterV2.getAmountsOut(amount, path) returns (uint[] memory amounts) {
            return amounts[1];
        } catch {
            return 0;
        }
    }

    /**
     * @notice Get best V3 quote across all fee tiers
     */
    function _getBestV3Quote(address token, uint256 amount)
        internal
        returns (uint256 bestQuote, uint24 bestFee)
    {
        for (uint256 i = 0; i < v3PoolFees.length; i++) {
            try pancakeQuoterV3.quoteExactInputSingle(
                token,
                WBNB,
                v3PoolFees[i],
                amount,
                0
            ) returns (uint256 quote) {
                if (quote > bestQuote) {
                    bestQuote = quote;
                    bestFee = v3PoolFees[i];
                }
            } catch {
                continue;
            }
        }
    }

    /**
     * @notice Execute V2 swap
     */
    function _swapV2(
        IERC20 token,
        uint256 amount,
        uint256 minAmountOut,
        uint256 deadline
    ) internal {
        token.approve(address(pancakeRouterV2), amount);

        address[] memory path = new address[](2);
        path[0] = address(token);
        path[1] = WBNB;

        try pancakeRouterV2.swapExactTokensForETH(
            amount,
            minAmountOut,
            path,
            address(this),
            deadline
        ) returns (uint[] memory amounts) {
            emit SingleSwapCompleted(
                msg.sender,
                address(token),
                amount,
                amounts[amounts.length - 1],
                RouterVersion.V2
            );
        } catch {
            token.transfer(msg.sender, amount);
        }
    }

    /**
     * @notice Execute V3 swap
     */
    function _swapV3(
        IERC20 token,
        uint256 amount,
        uint256 minAmountOut,
        uint24 fee
    ) internal {
        token.approve(address(pancakeRouterV3), amount);

        IPancakeV3SwapRouter.ExactInputSingleParams memory params =
            IPancakeV3SwapRouter.ExactInputSingleParams({
                tokenIn: address(token),
                tokenOut: WBNB,
                fee: fee,
                recipient: address(this),
                amountIn: amount,
                amountOutMinimum: minAmountOut,
                sqrtPriceLimitX96: 0
            });

        try pancakeRouterV3.exactInputSingle(params) returns (uint256 amountOut) {
            // Unwrap WBNB to BNB
            IERC20(WBNB).approve(address(pancakeRouterV2), amountOut);

            address[] memory path = new address[](1);
            path[0] = WBNB;

            pancakeRouterV2.swapExactTokensForETH(
                amountOut,
                amountOut,
                path,
                address(this),
                block.timestamp + 300
            );

            emit SingleSwapCompleted(
                msg.sender,
                address(token),
                amount,
                amountOut,
                RouterVersion.V3
            );
        } catch {
            token.transfer(msg.sender, amount);
        }
    }

    /**
     * @notice Get quotes from both V2 and V3
     */
    function getQuotes(address token, uint256 amount)
        external
        returns (uint256 v2Quote, uint256 v3Quote, uint24 v3Fee)
    {
        v2Quote = _getV2Quote(token, amount);
        (v3Quote, v3Fee) = _getBestV3Quote(token, amount);
    }

    /**
     * @notice Emergency withdraw
     */
    function emergencyWithdraw(address token, uint256 amount) external {
        if (amount == 0) return;

        if (token == address(0)) {
            (bool success, ) = payable(msg.sender).call{value: amount}("");
            if (!success) revert TransferFailed();
        } else {
            IERC20(token).transfer(msg.sender, amount);
        }
    }

    /**
     * @notice Add custom V3 pool fee
     */
    function addV3PoolFee(uint24 fee) external onlyOwner {
        if (fee == 0 || fee > 100000) revert InvalidFee();
        v3PoolFees.push(fee);
    }

    /**
     * @notice Receive BNB
     */
    receive() external payable {}
}

